	// FileDispute files a dispute against a data asset.
	FileDispute(context.Context, *MsgFileDispute) (*MsgFileDisputeResponse, error)
	// ResolveDispute resolves an open dispute (arbitrator only).
	ResolveDispute(context.Context, *MsgResolveDispute) (*MsgResolveDisputeResponse, error)
	// SellShares sells shares back to the bonding curve.
